import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o as d,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"IP Geolocation और User Management","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/ip-geolocation-and-user-management.md","filePath":"hi/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"hi/Other/ip-geolocation-and-user-management.md"};function u(h,e,g,m,b,f){return d(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-और-user-management" tabindex="-1">IP Geolocation और User Management <a class="header-anchor" href="#ip-geolocation-और-user-management" aria-label="Permalink to &quot;IP Geolocation और User Management&quot;">​</a></h1><p>IP geolocation uploader records, login devices और इसी तरह के logs में IP addresses को approximate locations में बदलता है।</p><p>Configure होने के बाद admin panel upload और access origins को ज़्यादा साफ़ दिखा सकता है। User Management suspicious IP addresses के upload access को block या restore करने की सुविधा भी देता है।</p><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>खोलें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>नया IP geolocation flow किसी एक map service पर depend करने के बजाय multiple sources support करता है।</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Display language चुनता है, जैसे English, Simplified Chinese, Japanese, French आदि।</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service के लिए MaxMind account ID।</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key।</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key। Chinese addresses और mainland China IPs के लिए useful।</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key। Multilingual IP geolocation support करता है।</td></tr></tbody></table><p>केवल वही services भरें जिनकी आपको ज़रूरत है। हर field configure करना ज़रूरी नहीं।</p><p>अगर कोई key नहीं दी गई है, तो ImgBed built-in free sources try करता है, लेकिन stability, language support और precision आपके configured service जितनी अच्छी न हो सकती है।</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>अगर आपको मुख्य रूप से Chinese addresses चाहिए:</p><ol><li>IP geolocation language को Simplified Chinese पर set करें।</li><li>Tencent Map Key configure करें।</li><li>Optional fallback के रूप में MaxMind या ipapi जोड़ें।</li></ol><p>अगर आपको मुख्य रूप से English या multilingual addresses चाहिए:</p><ol><li>अपनी ज़रूरत की language चुनें।</li><li>MaxMind Account ID और License Key configure करें।</li><li>बेहतर multilingual results चाहिए तो ipapi Key जोड़ें।</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind को चाहिए:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>MaxMind dashboard में account ID ढूँढें और License Keys page से License Key generate करें।</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>Generate होने के बाद Account ID और License Key को ImgBed में paste करके save करें।</p><p>MaxMind का free plan everyday use के लिए ठीक है, लेकिन request limits हैं। Quota exceed होने पर ImgBed दूसरे available sources try करता रहेगा।</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi APILayer API Key इस्तेमाल करता है।</p><p>ipapi console खोलें और वहाँ दिख रही API Key copy करें।</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>इसे ImgBed के <code>ipapi Key</code> field में paste करें और save करें।</p><p>ipapi multilingual IP geolocation support करता है और तब useful है जब आप selected language में addresses दिखाना चाहते हैं। इसके free plan में भी request limits हैं। Quota खत्म होने पर ImgBed दूसरे available sources try करता रहेगा।</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key Chinese addresses, खासकर mainland China IPs के लिए useful है।</p><p>Tencent Location Service में key बनाते समय enable करें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Creation के बाद key को <code>Tencent Map Key</code> में paste करें और save करें।</p><p>अगर आपको basic Chinese IP geolocation ही चाहिए, तो शुरुआत के लिए Tencent Map Key पर्याप्त है।</p><h2 id="user-management-में-क्या-देखें" tabindex="-1">User Management में क्या देखें <a class="header-anchor" href="#user-management-में-क्या-देखें" aria-label="Permalink to &quot;User Management में क्या देखें&quot;">​</a></h2><p>User Management admin panel के top से उपलब्ध है।</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management IP के आधार पर upload activity दिखाता है:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>Uploader source IP।</td></tr><tr><td>Address</td><td>IP से resolve हुई approximate location।</td></tr><tr><td>Total upload size</td><td>इस IP से uploaded total file size।</td></tr><tr><td>Upload count</td><td>इस IP से uploads की संख्या।</td></tr><tr><td>Upload allowed</td><td>On मतलब uploads allowed हैं। Off मतलब uploads blocked हैं।</td></tr></tbody></table><p>उस IP द्वारा uploaded files की list खोलने के लिए left side का arrow click करें।</p><p>File list में file name, preview, file size, moderation result, file status और upload time दिखते हैं। Uploads suspicious लगें तो पहले IP expand करें, files review करें, फिर decide करें कि future uploads block करने हैं या नहीं।</p><p>अगर IP suspicious है, तो <code>Upload allowed</code> off करें। आगे के uploads उस IP से block हो जाएँगे।</p><h2 id="search-sort-और-advanced-filters" tabindex="-1">Search, Sort और Advanced Filters <a class="header-anchor" href="#search-sort-और-advanced-filters" aria-label="Permalink to &quot;Search, Sort और Advanced Filters&quot;">​</a></h2><p>User Management के top पर IP source या address से search करें।</p><p>Recent uploaders, high-frequency uploaders या high-usage IPs ढूँढने के लिए time, upload count या total upload size से sort करें।</p><p>ज़्यादा गहराई से जाँच करनी हो तो advanced filters खोलें।</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters support करते हैं:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>Selected period में files upload करने वाले IPs दिखाता है।</td></tr><tr><td>Access status</td><td>Normal, blocked और similar states से filter करता है।</td></tr><tr><td>Allow/block list</td><td>Allowlist, blocklist या unset से filter करता है।</td></tr><tr><td>File type</td><td>Images, videos, audio, documents, code या other files upload करने वाले IPs दिखाता है।</td></tr><tr><td>File size</td><td>Uploaded file size range से filter करता है।</td></tr><tr><td>Age rating</td><td>Unset, General, R12+, R16+, R18 जैसी ratings से filter करता है।</td></tr><tr><td>File status</td><td>Abnormal files investigate करने के लिए current file status से filter करता है।</td></tr></tbody></table><p>Apply करने के लिए <code>Apply Filters</code> click करें। सभी data पर वापस जाने के लिए <code>Reset</code> इस्तेमाल करें।</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>Mobile पर User Management card layout में switch हो जाता है।</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>हर card में IP, address, total upload size, upload count और upload allowed switch दिखता है। Horizontal table scrolling के बिना users manage किए जा सकते हैं।</p><h2 id="अगर-location-गलत-लग-रही-है" tabindex="-1">अगर Location गलत लग रही है <a class="header-anchor" href="#अगर-location-गलत-लग-रही-है" aria-label="Permalink to &quot;अगर Location गलत लग रही है&quot;">​</a></h2><p>IP geolocation approximate होती है। यह exact street address नहीं है।</p><p>अगर user proxy, data center, cloud server या cross-border network के पीछे है, तो displayed location real location से अलग हो सकती है।</p><p>इस feature का इस्तेमाल rough origin समझने, abnormal uploads ढूँढने और blocking decisions में मदद के लिए करें। इसे precise tracking न मानें।</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address empty है</td><td>IP अभी resolve नहीं हुआ हो सकता है, या current source temporarily unavailable है।</td></tr><tr><td>Address language गलत है</td><td>IP geolocation language और उस language को support करने वाले source की configuration check करें।</td></tr><tr><td>Address data center दिखाता है</td><td>कई proxies, cloud servers और crawlers data center या ISP addresses की तरह दिखते हैं।</td></tr><tr><td>Upload count high है</td><td>इस IP को ध्यान से review करें और ज़रूरत हो तो uploads block करें।</td></tr><tr><td>Total upload size बड़ा है</td><td>Sort या filter करें, IP expand करें और specific files inspect करें।</td></tr><tr><td>Blocking के बाद restore करना है</td><td><code>Upload allowed</code> फिर से on करें।</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Other Settings में IP Geolocation खोलें</span></span>
<span class="line"><span>-&gt; IP geolocation language चुनें</span></span>
<span class="line"><span>-&gt; ज़रूरत के अनुसार MaxMind, Tencent Map या ipapi credentials भरें</span></span>
<span class="line"><span>-&gt; Settings save करें</span></span>
<span class="line"><span>-&gt; User Management खोलें</span></span>
<span class="line"><span>-&gt; IP source, address, total upload size और upload count review करें</span></span>
<span class="line"><span>-&gt; Abnormal IPs ढूँढने के लिए search, sort या advanced filters इस्तेमाल करें</span></span>
<span class="line"><span>-&gt; ज़रूरत के अनुसार uploads allow या block करें</span></span></code></pre></div>`,64)])])}const I=l(c,[["render",u]]);export{v as __pageData,I as default};
